#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X;
        scanf("%lld", &X);
        if (4 * X <= 1000) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

